public double myPow(double x, int n) {
    long N = n; // use long to handle Integer.MIN_VALUE
    if (N < 0) { x = 1.0 / x; N = -N; }
    double result = 1.0;
    while (N > 0) {
        if ((N & 1) == 1) result *= x;
        x *= x;
        N >>= 1;
    }
    return result;
}

